    if (fp4GemmType == FP4GemmType::W4A4_NVFP4_NVFP4)
    {
        if (sm >= 120)
        {
            return tkc::CutlassGemmConfig(tkc::CutlassTileConfigSM120::CtaShape128x128x256B,
