        config.randomSeed = nb::cast<OptVec<uint64_t>>(t[9]);
        config.topPDecay = nb::cast<OptVec<float>>(t[10]);
        config.topPMin = nb::cast<OptVec<float>>(t[11]);
        config.topPResetIds = nb::cast<OptVec<TokenIdType>>(t[12]);
